B.Z1=new A.eH("Wayang adalah seni pertunjukan tradisional Indonesia yang bercerita tentang kehidupan, nilai moral, dan petualangan tokoh-tokoh tertentu. Pertunjukan ini bisa menggunakan boneka (seperti wayang kulit atau wayang golek) atau dimainkan langsung oleh manusia (wayang orang). Biasanya, cerita yang dibawakan berasal dari kisah-kisah terkenal seperti Ramayana dan Mahabharata, tapi ada juga yang mengangkat cerita lokal atau kehidupan sehari-hari. Wayang tidak hanya untuk hiburan, tapi juga menjadi media untuk menyampaikan pesan tentang kebaikan, kejujuran, dan kebijaksanaan.\n\n",null,null,B.b_,null,null,null,null,null,null,null)
B.Z0=new A.eH("Di balik tampilannya yang tradisional, wayang sebenarnya punya makna yang dalam dan masih relevan sampai sekarang. Lewat karakter dan alur cerita, kita bisa belajar tentang cara menghadapi masalah, memilih yang benar, dan memahami berbagai sifat manusia. Bahkan, wayang sudah diakui dunia sebagai warisan budaya yang berharga. Jadi, meskipun terlihat \u201cjadul\u201d, wayang tetap keren untuk dipelajari karena mengandung banyak pelajaran hidup yang bisa diterapkan di zaman sekarang.",null,null,B.b_,null,null,null,null,null,null,null)
B.OM=s([B.Z1,B.Z0],t.VO)
B.ON=s([B.km,B.ko],A.ak("w<A4>"))
B.OQ=s([18,15,10,12,15,18,15,12,12],t.n)
B.OU=s([1116352408,1899447441,3049323471,3921009573,961987163,1508970993,2453635748,2870763221,3624381080,310598401,607225278,1426881987,1925078388,2162078206,2614888103,3248222580,3835390401,4022224774,264347078,604807628,770255983,1249150122,1555081692,1996064986,2554220882,2821834349,2952996808,3210313671,3336571891,3584528711,113926993,338241895,666307205,773529912,1294757372,1396182291,1695183700,1986661051,2177026350,2456956037,2730485921,2820302411,3259730800,3345764771,3516065817,3600352804,4094571909,275423344,430227734,506948616,659060556,883997877,958139571,1322822218,1537002063,1747873779,1955562222,2024104815,2227730452,2361852424,2428436474,2756734187,3204031479,3329325298],t.t)
B.cw={tanya:0,jawab:1}
B.Si=new A.b2(B.cw,["Kenapa Bisma memihak Kurawa padahal tahu mereka salah?","Bisma terikat sumpah setia kepada tahta Hastinapura, bukan kepada orangnya. Siapa pun yang duduk di tahta (saat itu Dretarastra dan Kurawa), wajib ia lindungi. Jadi ini konflik antara dharma (kewajiban) melawan kebenaran moral."],t.l)
B.Sl=new A.b2(B.cw,["Kenapa Drona juga memihak Kurawa?","Drona memihak Kurawa bukan cuma karena balas budi ke Hastinapura, tapi juga karena rasa sayang dan tanggung jawab terhadap Aswatama. Ia ingin anaknya memiliki kedudukan, kekuasaan, dan masa depan yang aman di kerajaan. Kurawa (khususnya Duryudana) memberikan posisi dan kehormatan itu, sehingga Drona merasa harus tetap setia."],t.l)
B.Sh=new A.b2(B.cw,["Kenapa Karna memihak Kurawa padahal dia kakak tertua Pandava?","Karna tidak tahu jati dirinya sejak kecil dan dibesarkan sebagai rakyat biasa. Saat dihina, hanya Duryudana yang mengangkat derajatnya. Karena itu, Karna memilih loyalitas dan balas budi kepada Duryudana dibanding hubungan darah yang baru ia ketahui belakangan."],t.l)
B.Sn=new A.b2(B.cw,["Kenapa Krishna tidak langsung menghentikan perang saja?","Krishna datang bukan untuk menghentikan takdir, tetapi untuk menegakkan dharma. Perang Bharatayuda dianggap sebagai cara untuk mengakhiri kejahatan yang sudah terlalu lama terjadi. Jadi perang ini adalah \u201cpembersihan\u201d dunia dari adharma."],t.l)
B.Sf=new A.b2(B.cw,["Apa sebenarnya isi ajaran Krishna pada Arjuna (Bhagavad Gita)?","Krishna mengajarkan bahwa manusia harus menjalankan kewajibannya tanpa terikat hasil (karma yoga). Arjuna diajarkan bahwa sebagai ksatria, ia harus berperang demi kebenaran, bukan karena emosi atau kepentingan pribadi."],t.l)
B.Sj=new A.b2(B.cw,["Kenapa Abimanyu bisa masuk Cakravyuha tapi tidak bisa keluar?","Abimanyu hanya mengetahui cara masuk formasi Cakravyuha sejak dalam kandungan, tapi tidak sempat mendengar cara keluar. Ia tetap maju demi tugas, namun akhirnya gugur karena dikeroyok. Ini menunjukkan keberanian tanpa pengetahuan lengkap bisa berakibat fatal."],t.l)
B.Se=new A.b2(B.cw,["Kenapa Duryudana begitu membenci Pandava?","Duryudana iri karena Pandawa lebih disukai rakyat, lebih kuat, dan lebih berbudi. Ditambah pengaruh Sengkuni, kebenciannya makin besar. Jadi akar masalahnya adalah iri hati + hasutan."],t.l)
B.Sm=new A.b2(B.cw,["Kenapa Yudistira yang dikenal jujur bisa kalah dalam permainan dadu?","Yudistira terjebak dalam dharma sebagai raja yang tidak boleh menolak undangan. Namun ia juga punya kelemahan, yaitu suka berjudi. Sengkuni memanfaatkan hal ini dengan kecurangan. Ini menunjukkan bahwa bahkan orang baik tetap punya celah kelemahan."],t.l)
B.Sg=new A.b2(B.cw,["Kenapa Krishna melanggar aturan perang dalam Bharatayuda?","Krishna memahami bahwa melawan kejahatan besar tidak selalu bisa dengan cara ideal. Ia membiarkan strategi seperti menjatuhkan Drona dengan tipu daya atau membunuh Karna saat tidak siap, karena tujuan utamanya adalah menegakkan dharma. Ini menunjukkan bahwa dalam kondisi tertentu, cara tidak sempurna bisa dipakai untuk mencapai tujuan yang benar."],t.l)
B.Sk=new A.b2(B.cw,["Kenapa Gandari mengutuk Krishna setelah perang berakhir?","Gandari sangat berduka karena kehilangan semua anaknya (Kurawa). Ia menyalahkan Krishna karena dianggap bisa mencegah perang tetapi tidak melakukannya. Karena kesedihan dan kemarahannya, Gandari mengutuk bahwa kelak bangsa Yadawa (keluarga Krishna) juga akan hancur. Dan benar, di kemudian hari kutukan itu terjadi. Ini menunjukkan bahwa bahkan kemenangan besar tetap meninggalkan luka dan dendam yang panjang."],t.l)
B.OV=s([B.Si,B.Sl,B.Sh,B.Sn,B.Sf,B.Sj,B.Se,B.Sm,B.Sg,B.Sk],t.m0)
